            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:10, marginBottom:20 }}>
              {[[property.beds > 0 ? property.beds : '—', property.beds > 0 ? 'Beds' : 'Studio'],[property.baths,'Baths'],[property.sqft.toLocaleString(),'Sq ft']].map(([v,l]) => (
